import { NavLink } from "react-router-dom";
import { FaCommentDots, FaChartBar } from "react-icons/fa";

function BottomNavbar() {
  return (
    <nav className="bottom-nav">
      <NavLink
        to="/"
        className={({ isActive }) =>
          isActive ? "nav-item active" : "nav-item"
        }
      >
        <FaCommentDots />
        <span>Feedback</span>
      </NavLink>

      <NavLink
        to="/dashboard"
        className={({ isActive }) =>
          isActive ? "nav-item active" : "nav-item"
        }
      >
        <FaChartBar />
        <span>Dashboard</span>
      </NavLink>
    </nav>
  );
}

export default BottomNavbar;
